package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetNullString_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        // DEFAULT nullString is null
        assertNull(format.getNullString());
    }

    @Test
    public void testGetNullString_CustomNullString() {
        // Create a new CSVFormat instance with nullString set to "NULL" using the withNullString method
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        assertEquals("NULL", format.getNullString());
    }

    @Test
    public void testGetNullString_WithNullStringViaWithNullString() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("N/A");
        assertEquals("N/A", format.getNullString());
    }

}
